import{_ as e,o as n,c as s,a2 as t}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Bounded contexts","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/05-bounded-contexts.md","filePath":"full-stack/arquitectura/ddd/05-bounded-contexts.md","lastUpdated":1782521464000}'),i={name:"full-stack/arquitectura/ddd/05-bounded-contexts.md"};function o(l,a,p,c,d,r){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="bounded-contexts" tabindex="-1">Bounded contexts <a class="header-anchor" href="#bounded-contexts" aria-label="Permalink to &quot;Bounded contexts&quot;">​</a></h1><p>Un bounded context es un limite dentro del cual un modelo tiene significado consistente.</p><h2 id="por-que-importan" tabindex="-1">Por que importan <a class="header-anchor" href="#por-que-importan" aria-label="Permalink to &quot;Por que importan&quot;">​</a></h2><p>En sistemas grandes, un unico modelo global suele fallar.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Customer en ventas</span></span>
<span class="line"><span>Customer en soporte</span></span>
<span class="line"><span>Customer en facturacion</span></span></code></pre></div><p>Pueden compartir datos, pero no necesariamente reglas, estados o responsabilidades.</p><h2 id="ejemplo" tabindex="-1">Ejemplo <a class="header-anchor" href="#ejemplo" aria-label="Permalink to &quot;Ejemplo&quot;">​</a></h2><p>Plataforma de cursos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Catalog</span></span>
<span class="line"><span>  Course</span></span>
<span class="line"><span>  Instructor</span></span>
<span class="line"><span>  PublicationStatus</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Learning</span></span>
<span class="line"><span>  Enrollment</span></span>
<span class="line"><span>  Progress</span></span>
<span class="line"><span>  LessonCompletion</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Billing</span></span>
<span class="line"><span>  Invoice</span></span>
<span class="line"><span>  Payment</span></span>
<span class="line"><span>  TaxData</span></span></code></pre></div><p>Cada contexto protege su lenguaje y su modelo.</p><h2 id="senales-de-contexto-distinto" tabindex="-1">Senales de contexto distinto <a class="header-anchor" href="#senales-de-contexto-distinto" aria-label="Permalink to &quot;Senales de contexto distinto&quot;">​</a></h2><ul><li>Las mismas palabras significan cosas distintas.</li><li>Equipos distintos cambian reglas sin coordinarse siempre.</li><li>Hay ciclos de vida diferentes.</li><li>Hay requisitos de escalado o seguridad distintos.</li><li>Las tablas compartidas generan conflictos constantes.</li></ul><h2 id="bounded-context-no-siempre-es-microservicio" tabindex="-1">Bounded context no siempre es microservicio <a class="header-anchor" href="#bounded-context-no-siempre-es-microservicio" aria-label="Permalink to &quot;Bounded context no siempre es microservicio&quot;">​</a></h2><p>Un bounded context puede vivir en:</p><ul><li>Un modulo dentro de un monolito.</li><li>Un paquete independiente.</li><li>Un servicio separado.</li><li>Un sistema externo.</li></ul><p>La frontera conceptual es mas importante que la frontera fisica.</p><h2 id="context-map" tabindex="-1">Context map <a class="header-anchor" href="#context-map" aria-label="Permalink to &quot;Context map&quot;">​</a></h2><p>Un context map muestra relaciones:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Catalog -&gt; Learning -&gt; Billing</span></span>
<span class="line"><span>   |          |          |</span></span>
<span class="line"><span>publica   matricula   factura</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Cada contexto tiene vocabulario propio.</li><li>Las dependencias entre contextos son explicitas.</li><li>No se comparte modelo interno por comodidad.</li><li>La integracion usa contratos claros.</li><li>La separacion fisica se decide despues de entender la frontera conceptual.</li></ul>`,21)])])}const h=e(i,[["render",o]]);export{m as __pageData,h as default};
